const items = $input.all();
const results = [];

for (const item of items) {
  const texto = item.json.text || '';

  // Normaliza: remove quebras de linha e espaços extras
  const textoNormalizado = texto.replace(/\s+/g, ' ');

  // Regex para boleto (47 dígitos)
  const regexBoleto = /\d{5}\.?\d{5}\s?\d{5}\.?\d{6}\s?\d{5}\.?\d{6}\s?\d\s?\d{14}/g;

  // Regex para concessionária (48 dígitos)
  const regexConcessionaria = /\d{11}-?\d\s*\d{11}-?\d\s*\d{11}-?\d\s*\d{11}-?\d/g;

  let linhaDigitavel = null;
  let tipoDocumento = null;

  // Tenta boleto primeiro
  const matchBoleto = textoNormalizado.match(regexBoleto);
  if (matchBoleto) {
    linhaDigitavel = matchBoleto[0];
    tipoDocumento = 'boleto';
  } else {
    // Tenta concessionária
    const matchConc = textoNormalizado.match(regexConcessionaria);
    if (matchConc) {
      linhaDigitavel = matchConc[0];
      tipoDocumento = 'concessionaria';
    }
  }

  // Cria novo objeto com todos os dados originais
  const novoItem = { ...item.json };

  if (linhaDigitavel) {
    const apenasNumeros = linhaDigitavel.replace(/\D/g, '');
    novoItem.linha_digitavel = linhaDigitavel;
    novoItem.linha_digitavel_numeros = apenasNumeros;
    novoItem.tipo_documento = tipoDocumento;
    novoItem.qtd_digitos = apenasNumeros.length;
  } else {
    novoItem.linha_digitavel = null;
    novoItem.linha_digitavel_numeros = null;
    novoItem.tipo_documento = 'ted';
    novoItem.erro = 'Linha digitável não encontrada - provável TED';
  }

  results.push({ json: novoItem });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
