const items = $input.all();

function modulo10(numero) {
  let soma = 0;
  let peso = 2;

  for (let i = numero.length - 1; i >= 0; i--) {
    let produto = parseInt(numero[i]) * peso;
    if (produto >= 10) {
      produto = Math.floor(produto / 10) + (produto % 10);
    }
    soma += produto;
    peso = peso === 2 ? 1 : 2;
  }

  const resto = soma % 10;
  return resto === 0 ? 0 : 10 - resto;
}

function modulo11Boleto(numero) {
  let soma = 0;
  let peso = 2;

  for (let i = numero.length - 1; i >= 0; i--) {
    soma += parseInt(numero[i]) * peso;
    peso = peso >= 9 ? 2 : peso + 1;
  }

  const resto = soma % 11;
  const dv = 11 - resto;

  if (dv === 0 || dv === 10 || dv === 11) {
    return 1;
  }
  return dv;
}

function modulo11Conc(numero) {
  let soma = 0;
  let peso = 2;

  for (let i = numero.length - 1; i >= 0; i--) {
    soma += parseInt(numero[i]) * peso;
    peso = peso >= 9 ? 2 : peso + 1;
  }

  const resto = soma % 11;
  const dv = 11 - resto;

  if (dv === 0 || dv === 10 || dv === 11) {
    return 0;
  }
  return dv;
}

for (const item of items) {
  const linha = item.json.linha_digitavel_numeros || '';
  const tipo = item.json.tipo_documento || '';
  const erros = [];

  if (tipo === 'boleto' && linha.length === 47) {

    // Campo 1: posicoes 0-8 (9 digitos) + DV na posicao 9
    const campo1 = linha.substring(0, 9);
    const dv1 = parseInt(linha.substring(9, 10));
    const dv1Calc = modulo10(campo1);

    // Campo 2: posicoes 10-19 (10 digitos) + DV na posicao 20
    const campo2 = linha.substring(10, 20);
    const dv2 = parseInt(linha.substring(20, 21));
    const dv2Calc = modulo10(campo2);

    // Campo 3: posicoes 21-30 (10 digitos) + DV na posicao 31
    const campo3 = linha.substring(21, 31);
    const dv3 = parseInt(linha.substring(31, 32));
    const dv3Calc = modulo10(campo3);

    // Campo 4: DV geral - posicao 32
    const dvGeral = parseInt(linha.substring(32, 33));

    // Campo 5: Fator vencimento (4) + Valor (10) - posicoes 33-46
    const fatorVencimento = linha.substring(33, 37);
    const valorStr = linha.substring(37, 47);

    // Monta codigo de barras (44 digitos) para validar DV geral
    // Estrutura: Banco(3) + Moeda(1) + DV(1) + Fator(4) + Valor(10) + CampoLivre(25)
    // Campo livre = pos 4-8 da linha (5 dig) + pos 10-19 (10 dig) + pos 21-30 (10 dig)
    const banco = linha.substring(0, 3);
    const moeda = linha.substring(3, 4);
    const campoLivre = linha.substring(4, 9) + linha.substring(10, 20) + linha.substring(21, 31);

    // Codigo de barras SEM o DV geral (43 digitos) para calcular
    const codigoBarrasSemDV = banco + moeda + fatorVencimento + valorStr + campoLivre;
    const dvGeralCalc = modulo11Boleto(codigoBarrasSemDV);

    // Validacoes
    if (dv1 !== dv1Calc) {
      erros.push('Campo 1: DV invalido (esperado ' + dv1Calc + ', encontrado ' + dv1 + ')');
    }
    if (dv2 !== dv2Calc) {
      erros.push('Campo 2: DV invalido (esperado ' + dv2Calc + ', encontrado ' + dv2 + ')');
    }
    if (dv3 !== dv3Calc) {
      erros.push('Campo 3: DV invalido (esperado ' + dv3Calc + ', encontrado ' + dv3 + ')');
    }
    if (dvGeral !== dvGeralCalc) {
      erros.push('DV Geral: invalido (esperado ' + dvGeralCalc + ', encontrado ' + dvGeral + ')');
    }

    // Dados extraidos
    item.json.banco_codigo = banco;
    item.json.moeda = moeda;
    item.json.dv_geral = dvGeral;
    item.json.fator_vencimento = fatorVencimento;
    item.json.valor_documento = (parseInt(valorStr) / 100).toFixed(2);

  } else if (tipo === 'concessionaria' && linha.length === 48) {

    // 4 blocos de 12 digitos (11 + DV)
    for (let i = 0; i < 4; i++) {
      const bloco = linha.substring(i * 12, i * 12 + 11);
      const dv = parseInt(linha.substring(i * 12 + 11, i * 12 + 12));
      const dvCalc11 = modulo11Conc(bloco);
      const dvCalc10 = modulo10(bloco);

      if (dv !== dvCalc11 && dv !== dvCalc10) {
        erros.push('Bloco ' + (i + 1) + ': DV invalido (esperado ' + dvCalc11 + ' ou ' + dvCalc10 + ', encontrado ' + dv + ')');
      }
    }

    // Dados extraidos
    item.json.segmento = linha.substring(0, 1);
    item.json.valor_documento = (parseInt(linha.substring(4, 15)) / 100).toFixed(2);

  } else {
    erros.push('Tipo de documento nao reconhecido ou tamanho invalido');
  }

  // Resultado final
  item.json.validacao_febraban_ok = erros.length === 0;
  item.json.validacao_febraban_erros = erros;
}

return items;

const items = $input.all();

function validarCNPJ(cnpj) {
  if (!cnpj || cnpj.length !== 14 || /^(\d)\1+$/.test(cnpj)) return false;

  let tamanho = cnpj.length - 2;
  let numeros = cnpj.substring(0, tamanho);
  let digitos = cnpj.substring(tamanho);
  let soma = 0;
  let pos = tamanho - 7;

  for (let i = tamanho; i >= 1; i--) {
    soma += numeros.charAt(tamanho - i) * pos--;
    if (pos < 2) pos = 9;
  }

  let resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
  if (resultado !== parseInt(digitos.charAt(0))) return false;

  tamanho = tamanho + 1;
  numeros = cnpj.substring(0, tamanho);
  soma = 0;
  pos = tamanho - 7;

  for (let i = tamanho; i >= 1; i--) {
    soma += numeros.charAt(tamanho - i) * pos--;
    if (pos < 2) pos = 9;
  }

  resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
  return resultado === parseInt(digitos.charAt(1));
}

function validarCPF(cpf) {
  if (!cpf || cpf.length !== 11 || /^(\d)\1+$/.test(cpf)) return false;

  let soma = 0;
  for (let i = 0; i < 9; i++) soma += parseInt(cpf[i]) * (10 - i);
  let resto = (soma * 10) % 11;
  if (resto === 10 || resto === 11) resto = 0;
  if (resto !== parseInt(cpf[9])) return false;

  soma = 0;
  for (let i = 0; i < 10; i++) soma += parseInt(cpf[i]) * (11 - i);
  resto = (soma * 10) % 11;
  if (resto === 10 || resto === 11) resto = 0;
  return resto === parseInt(cpf[10]);
}

function tentarCorrigirCNPJ(cnpj) {
  // Se tem 15 dígitos, tenta remover cada dígito duplicado
  if (cnpj.length === 15) {
    for (let i = 0; i < cnpj.length; i++) {
      const tentativa = cnpj.substring(0, i) + cnpj.substring(i + 1);
      if (validarCNPJ(tentativa)) {
        return tentativa;
      }
    }
  }
  // Se tem 13 dígitos, tenta adicionar zero no início
  if (cnpj.length === 13) {
    const tentativa = '0' + cnpj;
    if (validarCNPJ(tentativa)) {
      return tentativa;
    }
  }
  return cnpj;
}

function tentarCorrigirCPF(cpf) {
  // Se tem 12 dígitos, tenta remover cada dígito duplicado
  if (cpf.length === 12) {
    for (let i = 0; i < cpf.length; i++) {
      const tentativa = cpf.substring(0, i) + cpf.substring(i + 1);
      if (validarCPF(tentativa)) {
        return tentativa;
      }
    }
  }
  // Se tem 10 dígitos, tenta adicionar zero no início
  if (cpf.length === 10) {
    const tentativa = '0' + cpf;
    if (validarCPF(tentativa)) {
      return tentativa;
    }
  }
  return cpf;
}

function tratarDigito(digito) {
  if (!digito) return '';
  const digitoStr = digito.toString().toUpperCase();
  if (digitoStr === 'X') return '0';
  return digitoStr;
}

for (const item of items) {
  let dados;
  try {
    let content = '';

    if (item.json.output && item.json.output[0]?.content?.[0]?.text) {
      content = item.json.output[0].content[0].text;
    } else if (item.json.message?.content) {
      content = item.json.message.content;
    } else if (item.json.choices?.[0]?.message?.content) {
      content = item.json.choices[0].message.content;
    } else if (typeof item.json === 'string') {
      content = item.json;
    }

    dados = JSON.parse(content);
  } catch (e) {
    item.json.validacao_ted_ok = false;
    item.json.validacao_ted_erros = ['Erro ao processar resposta da IA: ' + e.message];
    continue;
  }

  const erros = [];
  let cnpjCpf = (dados.favorecido_cnpj_cpf || '').toString().replace(/\D/g, '');
  let cnpjCorrigido = false;

  // Tentar autocorrigir CNPJ/CPF se tamanho inválido
  if (cnpjCpf.length === 15 || cnpjCpf.length === 13) {
    const corrigido = tentarCorrigirCNPJ(cnpjCpf);
    if (corrigido.length === 14 && validarCNPJ(corrigido)) {
      cnpjCpf = corrigido;
      cnpjCorrigido = true;
    }
  } else if (cnpjCpf.length === 12 || cnpjCpf.length === 10) {
    const corrigido = tentarCorrigirCPF(cnpjCpf);
    if (corrigido.length === 11 && validarCPF(corrigido)) {
      cnpjCpf = corrigido;
      cnpjCorrigido = true;
    }
  }

  if (cnpjCpf.startsWith('05385049')) {
    erros.push('CNPJ do favorecido é na verdade do pagador (Air Canada)');
  }

  if (cnpjCpf.length === 14) {
    if (!validarCNPJ(cnpjCpf)) {
      erros.push('CNPJ do favorecido inválido');
    }
  } else if (cnpjCpf.length === 11) {
    if (!validarCPF(cnpjCpf)) {
      erros.push('CPF do favorecido inválido');
    }
  } else if (cnpjCpf.length > 0) {
    erros.push('CNPJ/CPF do favorecido com tamanho inválido: ' + cnpjCpf.length + ' dígitos');
  } else {
    erros.push('CNPJ/CPF do favorecido não encontrado');
  }

  if (!dados.favorecido_nome) {
    erros.push('Nome do favorecido não encontrado');
  }
  if (!dados.banco_codigo) {
    erros.push('Código do banco não encontrado');
  }
  if (!dados.agencia) {
    erros.push('Agência não encontrada');
  }
  if (!dados.conta) {
    erros.push('Conta não encontrada');
  }
  if (!dados.valor || dados.valor <= 0) {
    erros.push('Valor inválido ou não encontrado');
  }

  // Data de vencimento - se não tiver, define para 10 dias a partir de hoje
  let dataVencimento = dados.data_vencimento || '';
  if (!dataVencimento) {
    const hoje = new Date();
    hoje.setDate(hoje.getDate() + 10);
    const ano = hoje.getFullYear();
    const mes = String(hoje.getMonth() + 1).padStart(2, '0');
    const dia = String(hoje.getDate()).padStart(2, '0');
    dataVencimento = `${ano}-${mes}-${dia}`;
  }

  item.json.favorecido_cnpj_cpf = cnpjCpf;
  item.json.cnpj_corrigido = cnpjCorrigido;
  item.json.favorecido_nome = dados.favorecido_nome || '';
  item.json.banco_codigo = dados.banco_codigo || '';
  item.json.banco_nome = dados.banco_nome || '';
  item.json.agencia = dados.agencia || '';
  item.json.agencia_digito = tratarDigito(dados.agencia_digito);
  item.json.conta = dados.conta || '';
  item.json.conta_digito = tratarDigito(dados.conta_digito);
  item.json.tipo_conta = dados.tipo_conta || '';
  item.json.valor = dados.valor || 0;
  item.json.data_vencimento = dataVencimento;
  item.json.descricao = dados.descricao || '';

  item.json.validacao_ted_ok = erros.length === 0;
  item.json.validacao_ted_erros = erros;
}

return items;

const items = $input.all();
for (const item of items) {
  // Pega o valor da primeira extração (Validar_TED)
  const valorExtracao1 = parseFloat($('Validar_TED').item.json.valor) || 0;

  // Pega o valor da segunda extração (Verificar_Valor_TED_IA)
  let valorExtracao2 = 0;
  try {
    const content = item.json.output?.[0]?.content?.[0]?.text || '';
    valorExtracao2 = parseFloat(content) || 0;
  } catch (e) {
    valorExtracao2 = 0;
  }

  // Compara os valores (100% iguais)
  const valoresIguais = valorExtracao1.toFixed(2) === valorExtracao2.toFixed(2);

  // Verificar se dados bancários estão preenchidos
  function campoVazio(valor) {
    if (!valor) return true;
    const limpo = String(valor).trim().toLowerCase();
    return limpo === '' || limpo === 'null' || limpo === 'n/a' || limpo === '-' || limpo === '----';
  }

  const banco = $('Validar_TED').item.json.banco_codigo;
  const agencia = $('Validar_TED').item.json.agencia;
  const conta = $('Validar_TED').item.json.conta;

  const faltamDadosBancarios = campoVazio(banco) || campoVazio(agencia) || campoVazio(conta);

  // Define o status baseado nas regras
  let status = '';
  if (!valoresIguais) {
    status = 'aguardando_revisao';
  } else if (valorExtracao1 > 20000) {
    status = 'aguardando_revisao';
  } else if (faltamDadosBancarios) {
    status = 'aguardando_revisao';
  } else {
    status = 'aprovado';
  }

  // Adiciona os dados ao item
  item.json.valor_extracao_1 = valorExtracao1;
  item.json.valor_extracao_2 = valorExtracao2;
  item.json.valores_iguais = valoresIguais;
  item.json.status = status;
  item.json.faltam_dados_bancarios = faltamDadosBancarios;

  // Copia dados do Validar_TED
  item.json.favorecido_cnpj_cpf = $('Validar_TED').item.json.favorecido_cnpj_cpf;
  item.json.favorecido_nome = $('Validar_TED').item.json.favorecido_nome;
  item.json.banco_codigo = $('Validar_TED').item.json.banco_codigo;
  item.json.banco_nome = $('Validar_TED').item.json.banco_nome;
  item.json.agencia = $('Validar_TED').item.json.agencia;
  item.json.agencia_digito = $('Validar_TED').item.json.agencia_digito;
  item.json.conta = $('Validar_TED').item.json.conta;
  item.json.conta_digito = $('Validar_TED').item.json.conta_digito;
  item.json.tipo_conta = $('Validar_TED').item.json.tipo_conta;
  item.json.valor = valorExtracao1;
  item.json.data_vencimento = $('Validar_TED').item.json.data_vencimento;
  item.json.descricao = $('Validar_TED').item.json.descricao;
  item.json.validacao_ted_ok = $('Validar_TED').item.json.validacao_ted_ok;
  item.json.validacao_ted_erros = $('Validar_TED').item.json.validacao_ted_erros;
}
return items;

const items = $input.all();

for (const item of items) {
  const documento = item.json.favorecido_cnpj_cpf || '';

  if (documento.length === 14) {
    item.json.tipo_documento = 'pj';
    item.json.campo_busca = 'cnpj';
  } else if (documento.length === 11) {
    item.json.tipo_documento = 'pf';
    item.json.campo_busca = 'cpf';
  } else {
    item.json.tipo_documento = 'desconhecido';
    item.json.campo_busca = 'cnpj';
  }
}

return items;

const items = $input.all();

// Pega o nome do cedente e descrição da IA
let nomeCedente = '';
let descricao = '';

try {
  const outputIA = $('Extrair_Cedente_Conc_IA').first().json;
  const textoIA = outputIA.output?.[0]?.content?.[0]?.text || '';

  // Tenta fazer parse do JSON
  try {
    const dadosIA = JSON.parse(textoIA);
    nomeCedente = dadosIA.cedente_nome || '';
    descricao = dadosIA.descricao || '';
  } catch (e) {
    // Se não for JSON, assume que é só o nome (formato antigo)
    nomeCedente = textoIA.trim();
    descricao = '';
  }
} catch (e) {
  nomeCedente = '';
  descricao = '';
}

// Pega os dados do nó Boleto_ou_Concessionaria (anterior à IA)
const dadosAnteriores = $('Boleto_ou_Concessionaria').first().json;
const linha = dadosAnteriores.linha_digitavel_numeros || '';
const erros = [];

// Monta código de barras a partir da linha digitável (remove DVs)
const codigoBarras = linha.substring(0, 11) + linha.substring(12, 23) + linha.substring(24, 35) + linha.substring(36, 47);

// Extrai data de vencimento (posições 19-26 do código de barras - AAAAMMDD)
let dataVencimento = '';
const dataStr = codigoBarras.substring(19, 27);
if (dataStr && dataStr.length === 8 && dataStr !== '00000000') {
  const ano = dataStr.substring(0, 4);
  const mes = dataStr.substring(4, 6);
  const dia = dataStr.substring(6, 8);
  dataVencimento = `${ano}-${mes}-${dia}`;
}

// Valida campos obrigatórios
if (!dadosAnteriores.valor_documento || parseFloat(dadosAnteriores.valor_documento) <= 0) {
  erros.push('Valor do documento não encontrado ou inválido');
}

if (!dataVencimento) {
  erros.push('Data de vencimento não encontrada');
}

if (!linha || linha.length !== 48) {
  erros.push('Linha digitável inválida');
}

return [{
  json: {
    linha_digitavel_numeros: linha,
    valor_documento: dadosAnteriores.valor_documento,
    segmento: dadosAnteriores.segmento,
    data_vencimento: dataVencimento,
    tipo_pagamento: 'concessionaria',
    status: 'aprovado',
    nome_cedente: nomeCedente,
    descricao: descricao,
    validacao_conc_ok: erros.length === 0,
    validacao_conc_erros: erros
  }
}];

