function validarCNPJ(cnpj) {
  if (!cnpj || cnpj.length !== 14 || /^(\d)\1+$/.test(cnpj)) return false;
  let tamanho = cnpj.length - 2;
  let numeros = cnpj.substring(0, tamanho);
  let digitos = cnpj.substring(tamanho);
  let soma = 0;
  let pos = tamanho - 7;
  for (let i = tamanho; i >= 1; i--) {
    soma += numeros.charAt(tamanho - i) * pos--;
    if (pos < 2) pos = 9;
  }
  let resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
  if (resultado !== parseInt(digitos.charAt(0))) return false;
  tamanho = tamanho + 1;
  numeros = cnpj.substring(0, tamanho);
  soma = 0;
  pos = tamanho - 7;
  for (let i = tamanho; i >= 1; i--) {
    soma += numeros.charAt(tamanho - i) * pos--;
    if (pos < 2) pos = 9;
  }
  resultado = soma % 11 < 2 ? 0 : 11 - soma % 11;
  return resultado === parseInt(digitos.charAt(1));
}

function validarCPF(cpf) {
  if (!cpf || cpf.length !== 11 || /^(\d)\1+$/.test(cpf)) return false;
  let soma = 0;
  for (let i = 0; i < 9; i++) soma += parseInt(cpf[i]) * (10 - i);
  let resto = (soma * 10) % 11;
  if (resto === 10 || resto === 11) resto = 0;
  if (resto !== parseInt(cpf[9])) return false;
  soma = 0;
  for (let i = 0; i < 10; i++) soma += parseInt(cpf[i]) * (11 - i);
  resto = (soma * 10) % 11;
  if (resto === 10 || resto === 11) resto = 0;
  return resto === parseInt(cpf[10]);
}

function tentarCorrigirCNPJ(cnpj) {
  // Se tem 15 dígitos, tenta remover cada dígito
  if (cnpj.length === 15) {
    for (let i = 0; i < cnpj.length; i++) {
      const tentativa = cnpj.substring(0, i) + cnpj.substring(i + 1);
      if (validarCNPJ(tentativa)) return tentativa;
    }
  }
  // Se tem 13 dígitos, tenta adicionar zero no início
  if (cnpj.length === 13) {
    const tentativa = '0' + cnpj;
    if (validarCNPJ(tentativa)) return tentativa;
  }
  // Se tem 14 dígitos mas é inválido, tenta trocar cada dígito
  if (cnpj.length === 14 && !validarCNPJ(cnpj)) {
    // Tenta adicionar zero no início (caso perdeu zero e ganhou dígito extra)
    for (let i = 0; i < cnpj.length; i++) {
      // Remove posição i e adiciona 0 no início
      const tentativa = '0' + cnpj.substring(0, i) + cnpj.substring(i + 1);
      if (tentativa.length === 14 && validarCNPJ(tentativa)) return tentativa;
    }
  }
  return cnpj;
}

function tentarCorrigirCPF(cpf) {
  if (cpf.length === 12) {
    for (let i = 0; i < cpf.length; i++) {
      const tentativa = cpf.substring(0, i) + cpf.substring(i + 1);
      if (validarCPF(tentativa)) return tentativa;
    }
  }
  if (cpf.length === 10) {
    const tentativa = '0' + cpf;
    if (validarCPF(tentativa)) return tentativa;
  }
  return cpf;
}

for (let i = 0; i < todosFEBRABAN.length; i++) {
  let cedenteCnpjCpf = '';
  let cedenteNome = '';
  let descricao = '';
  let cnpjCorrigido = false;

  try {
    const outputIA = todosIA[i]?.json || {};
    const content = outputIA.output?.[0]?.content?.[0]?.text || '';
    const dadosIA = JSON.parse(content);
    cedenteCnpjCpf = (dadosIA.cedente_cnpj_cpf || '').toString().replace(/\D/g, '');
    cedenteNome = dadosIA.cedente_nome || '';
    descricao = dadosIA.descricao || '';
  } catch (e) {
    cedenteCnpjCpf = '';
    cedenteNome = '';
    descricao = '';
  }

  // Validar e autocorrigir CNPJ/CPF
  if (cedenteCnpjCpf.length >= 13 && cedenteCnpjCpf.length <= 15) {
    if (!validarCNPJ(cedenteCnpjCpf)) {
      const corrigido = tentarCorrigirCNPJ(cedenteCnpjCpf);
      if (validarCNPJ(corrigido)) {
        cedenteCnpjCpf = corrigido;
        cnpjCorrigido = true;
      }
    }
  } else if (cedenteCnpjCpf.length >= 10 && cedenteCnpjCpf.length <= 12) {
    if (!validarCPF(cedenteCnpjCpf)) {
      const corrigido = tentarCorrigirCPF(cedenteCnpjCpf);
      if (validarCPF(corrigido)) {
        cedenteCnpjCpf = corrigido;
        cnpjCorrigido = true;
      }
    }
  }

  // Pega dados do FEBRABAN
  const dadosFEBRABAN = todosFEBRABAN[i]?.json || {};
  const arquivoId = dadosFEBRABAN.id || '';
  const linha = dadosFEBRABAN.linha_digitavel_numeros || '';
  const valorDocumento = dadosFEBRABAN.valor_documento || '0';
  const bancoCodigo = dadosFEBRABAN.banco_codigo || '';
  const fatorVencimento = dadosFEBRABAN.fator_vencimento || '';

  // Calcula data de vencimento
  let dataVencimento = '';
  if (fatorVencimento && fatorVencimento !== '0000') {
    const fator = parseInt(fatorVencimento);
    const dataBaseCiclo1 = Date.UTC(1997, 9, 7);
    const dataTesteCiclo1 = new Date(dataBaseCiclo1 + (fator * 24 * 60 * 60 * 1000));

    let dataFinal;
    if (dataTesteCiclo1.getUTCFullYear() < 2025) {
      const dataBaseCiclo2 = Date.UTC(2025, 1, 22);
      dataFinal = new Date(dataBaseCiclo2 + ((fator - 1000) * 24 * 60 * 60 * 1000));
    } else {
      dataFinal = dataTesteCiclo1;
    }

    const ano = dataFinal.getUTCFullYear();
    const mes = String(dataFinal.getUTCMonth() + 1).padStart(2, '0');
    const dia = String(dataFinal.getUTCDate()).padStart(2, '0');
    dataVencimento = `${ano}-${mes}-${dia}`;
  }

  // Validações
  const erros = [];
  if (!cedenteNome) erros.push('Nome do cedente não encontrado');
  if (!valorDocumento || parseFloat(valorDocumento) <= 0) erros.push('Valor do documento inválido');
  if (!dataVencimento) erros.push('Data de vencimento não encontrada');
  if (!linha || linha.length !== 47) erros.push('Linha digitável inválida');

  // Validar CNPJ/CPF
  if (cedenteCnpjCpf.length === 14 && !validarCNPJ(cedenteCnpjCpf)) {
    erros.push('CNPJ do cedente inválido: ' + cedenteCnpjCpf);
  } else if (cedenteCnpjCpf.length === 11 && !validarCPF(cedenteCnpjCpf)) {
    erros.push('CPF do cedente inválido: ' + cedenteCnpjCpf);
  }

  const temCnpj = (cedenteCnpjCpf.length === 14 && validarCNPJ(cedenteCnpjCpf)) || 
                   (cedenteCnpjCpf.length === 11 && validarCPF(cedenteCnpjCpf));

  resultados.push({
    json: {
      arquivo_id: arquivoId,
      linha_digitavel_numeros: linha,
      valor_documento: valorDocumento,
      banco_codigo: bancoCodigo,
      data_vencimento: dataVencimento,
      cedente_cnpj_cpf: cedenteCnpjCpf,
      cnpj_corrigido: cnpjCorrigido,
      cedente_nome: cedenteNome,
      descricao: descricao,
      tem_cnpj: temCnpj,
      tipo_pagamento: 'boleto',
      validacao_boleto_ok: erros.length === 0,
      validacao_boleto_erros: erros
    }
  });
}

return resultados;

