const items = $input.all();

function modulo10(numero) {
  let soma = 0;
  let peso = 2;

  for (let i = numero.length - 1; i >= 0; i--) {
    let produto = parseInt(numero[i]) * peso;
    if (produto >= 10) {
      produto = Math.floor(produto / 10) + (produto % 10);
    }
    soma += produto;
    peso = peso === 2 ? 1 : 2;
  }

  const resto = soma % 10;
  return resto === 0 ? 0 : 10 - resto;
}

function modulo11Boleto(numero) {
  let soma = 0;
  let peso = 2;

  for (let i = numero.length - 1; i >= 0; i--) {
    soma += parseInt(numero[i]) * peso;
    peso = peso >= 9 ? 2 : peso + 1;
  }

  const resto = soma % 11;
  const dv = 11 - resto;

  if (dv === 0 || dv === 10 || dv === 11) {
    return 1;
  }
  return dv;
}

function modulo11Conc(numero) {
  let soma = 0;
  let peso = 2;

  for (let i = numero.length - 1; i >= 0; i--) {
    soma += parseInt(numero[i]) * peso;
    peso = peso >= 9 ? 2 : peso + 1;
  }

  const resto = soma % 11;
  const dv = 11 - resto;

  if (dv === 0 || dv === 10 || dv === 11) {
    return 0;
  }
  return dv;
}

for (const item of items) {
  const linha = item.json.linha_digitavel_numeros || '';
  const tipo = item.json.tipo_documento || '';
  const erros = [];

  if (tipo === 'boleto' && linha.length === 47) {

    // Campo 1: posicoes 0-8 (9 digitos) + DV na posicao 9
    const campo1 = linha.substring(0, 9);
    const dv1 = parseInt(linha.substring(9, 10));
    const dv1Calc = modulo10(campo1);

    // Campo 2: posicoes 10-19 (10 digitos) + DV na posicao 20
    const campo2 = linha.substring(10, 20);
    const dv2 = parseInt(linha.substring(20, 21));
    const dv2Calc = modulo10(campo2);

    // Campo 3: posicoes 21-30 (10 digitos) + DV na posicao 31
    const campo3 = linha.substring(21, 31);
    const dv3 = parseInt(linha.substring(31, 32));
    const dv3Calc = modulo10(campo3);

    // Campo 4: DV geral - posicao 32
    const dvGeral = parseInt(linha.substring(32, 33));

    // Campo 5: Fator vencimento (4) + Valor (10) - posicoes 33-46
    const fatorVencimento = linha.substring(33, 37);
    const valorStr = linha.substring(37, 47);

    // Monta codigo de barras (44 digitos) para validar DV geral
    // Estrutura: Banco(3) + Moeda(1) + DV(1) + Fator(4) + Valor(10) + CampoLivre(25)
    // Campo livre = pos 4-8 da linha (5 dig) + pos 10-19 (10 dig) + pos 21-30 (10 dig)
    const banco = linha.substring(0, 3);
    const moeda = linha.substring(3, 4);
    const campoLivre = linha.substring(4, 9) + linha.substring(10, 20) + linha.substring(21, 31);

    // Codigo de barras SEM o DV geral (43 digitos) para calcular
    const codigoBarrasSemDV = banco + moeda + fatorVencimento + valorStr + campoLivre;
    const dvGeralCalc = modulo11Boleto(codigoBarrasSemDV);

    // Validacoes
    if (dv1 !== dv1Calc) {
      erros.push('Campo 1: DV invalido (esperado ' + dv1Calc + ', encontrado ' + dv1 + ')');
    }
    if (dv2 !== dv2Calc) {
      erros.push('Campo 2: DV invalido (esperado ' + dv2Calc + ', encontrado ' + dv2 + ')');
    }
    if (dv3 !== dv3Calc) {
      erros.push('Campo 3: DV invalido (esperado ' + dv3Calc + ', encontrado ' + dv3 + ')');
    }
    if (dvGeral !== dvGeralCalc) {
      erros.push('DV Geral: invalido (esperado ' + dvGeralCalc + ', encontrado ' + dvGeral + ')');
    }

    // Dados extraidos
    item.json.banco_codigo = banco;
    item.json.moeda = moeda;
    item.json.dv_geral = dvGeral;
    item.json.fator_vencimento = fatorVencimento;
    item.json.valor_documento = (parseInt(valorStr) / 100).toFixed(2);

  } else if (tipo === 'concessionaria' && linha.length === 48) {

    // 4 blocos de 12 digitos (11 + DV)
    for (let i = 0; i < 4; i++) {
      const bloco = linha.substring(i * 12, i * 12 + 11);
      const dv = parseInt(linha.substring(i * 12 + 11, i * 12 + 12));
      const dvCalc11 = modulo11Conc(bloco);
      const dvCalc10 = modulo10(bloco);

      if (dv !== dvCalc11 && dv !== dvCalc10) {
        erros.push('Bloco ' + (i + 1) + ': DV invalido (esperado ' + dvCalc11 + ' ou ' + dvCalc10 + ', encontrado ' + dv + ')');
      }
    }

    // Dados extraidos
    item.json.segmento = linha.substring(0, 1);
    item.json.valor_documento = (parseInt(linha.substring(4, 15)) / 100).toFixed(2);

  } else {
    erros.push('Tipo de documento nao reconhecido ou tamanho invalido');
  }

  // Resultado final
  item.json.validacao_febraban_ok = erros.length === 0;
  item.json.validacao_febraban_erros = erros;
}

return items;

